//! Ackermann Admission Gate — polyglot edition.
//!
//! Wraps the `distributed_inference::ackermann_certificate` kernel and
//! exposes an admission-gate surface for the two polyglot recursion
//! guards: `gnexec.rs` (call-depth) and `multi_file.rs` (BFS import).
//!
//! Mirrors the Lean module `Gnosis/AckermannRuntimeCertificate.lean`
//! plus `Gnosis/AckermannAdmissionContract.lean` (sibling in this
//! fanout). The gate distinguishes primitive-recursive growth (admit)
//! from non-primitive-recursive growth (reject), using the
//! finite-difference test on the calibration window n ∈ [0, 3].
//!
//! ## Architecture status (inline discovery doc)
//!
//! Both consumers are wired: `gnexec.rs` runs `gate_call_depth` and
//! `multi_file.rs` runs `gate_bfs_fanout` as reject-before-invoke
//! pre-passes. On admit, the legacy `max_call_depth + deadline` /
//! `max_depth` guards remain in force by default. The FOIL vacuum
//! (`vacuum_licensed`) is the opt-in second half: a certified
//! `AdmitPrimitiveRecursive` verdict licenses the caller to drop the
//! growth-class guards — the wall-clock deadline in `gnexec.rs`, the
//! BFS depth truncation in `multi_file.rs` — because the certificate
//! makes them vacuous on the calibration window. Physical machine
//! guards (the OS-stack call-depth backstop) are NOT growth-class
//! claims and stay in force even inside the vacuum.
//!
//! ## Verdict semantics
//!
//! - `AdmitPrimitiveRecursive { degree_estimate: d }` — the finite-
//!   difference detector pinned a polynomial envelope of degree d.
//!   Caller may proceed with NO additional depth/time guard.
//! - `AdmitWithLegacyGuards` — degree ≥ 4 (the finite-difference
//!   detector's tight reach is degree 3). Honest "admit, but the
//!   calibration window doesn't bind tightly enough to drop the
//!   belt-and-suspenders depth+time guards yet."
//! - `Reject { reason }` — strong rejection signal:
//!     * `NonPolynomialGrowth` — the (d=3)+1-th forward difference is
//!       non-zero, so growth is super-polynomial / Ackermann-class.
//!     * `ExceedsCeilingAtCalibration` — at some n ∈ {0,1,2,3} the
//!       target's step count is already at or above the Ackermann
//!       ceiling. This is the strongest reject signal — even the
//!       calibration window saturates.
//!     * `InvalidStepCount` — defensive sentinel; reserved for future
//!       callers that wrap a fallible probe.

#![allow(dead_code)]

use distributed_inference::ackermann_certificate::{
    certify, polynomial_degree_estimate, AckermannCertificate,
};

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum AdmissionVerdict {
    /// Target's growth is bounded by a primitive-recursive class.
    /// Caller may proceed without further depth/time checks.
    AdmitPrimitiveRecursive { degree_estimate: u32 },
    /// Target's growth is bounded but exceeds the polynomial
    /// detector's reach. Admit, but apply the legacy depth+time guards.
    AdmitWithLegacyGuards,
    /// Target's growth class is non-polynomial / Ackermann-shaped.
    /// Caller MUST reject before invoking.
    Reject { reason: RejectReason },
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum RejectReason {
    /// Finite-difference estimator returned None (non-polynomial).
    NonPolynomialGrowth,
    /// At calibration n=3, target exceeded the Ackermann ceiling (27).
    /// This is the strongest reject signal — even at n=3 the algorithm
    /// is already at or above 100%-Ackermann.
    ExceedsCeilingAtCalibration,
    /// Target panicked or returned an obviously-invalid step count
    /// (e.g., u64::MAX as a defensive sentinel) at some calibration
    /// point.
    InvalidStepCount,
}

#[derive(Debug, Clone)]
pub struct AdmissionReport {
    pub verdict: AdmissionVerdict,
    pub certificates: Vec<AckermannCertificate>,
    pub polynomial_degree: Option<u32>,
    /// Max percentile seen on calibration window.
    pub max_percentile: u32,
}

/// Sample size for the finite-difference polynomial detector. The
/// kernel requires `>= 5` to exercise the degree-3 (d4) path. We use
/// 8 to keep one extra sample of headroom while staying cheap.
const POLY_SAMPLE_SIZE: u32 = 8;

/// Tightest degree the kernel's finite-difference detector can pin.
/// Polynomials of degree > 3 still register as "Some(d)"? No — the
/// kernel only checks d1..d4 and returns None above d=3. So any
/// Some(d) from the kernel satisfies d ≤ 3 already. We keep this
/// constant explicit so the `AdmitWithLegacyGuards` branch is
/// reachable if the kernel ever grows to detect higher degrees
/// without this module having to change in lockstep.
const POLY_DETECTOR_TIGHT_DEGREE: u32 = 3;

/// Decide admission for a runtime-estimate function. The caller
/// supplies a `target: Fn(u32) -> u64` that estimates the step count
/// at input size n. The gate runs `certify(target, 3)` plus
/// `polynomial_degree_estimate(target, 8)` and emits a verdict.
///
/// Verdict resolution order (first match wins):
///   1. Any calibration percentile > 100 ⇒ Reject(ExceedsCeilingAtCalibration).
///   2. polynomial_degree_estimate is Some(d) with d ≤ 3 ⇒ AdmitPrimitiveRecursive.
///   3. polynomial_degree_estimate is Some(d) with d > 3 ⇒ AdmitWithLegacyGuards.
///   4. polynomial_degree_estimate is None ⇒ Reject(NonPolynomialGrowth).
pub fn decide_admission<F>(target: F) -> AdmissionReport
where
    F: Fn(u32) -> u64 + Copy,
{
    let certificates = certify(target, 3);
    let max_percentile = certificates.iter().map(|c| c.percentile).max().unwrap_or(0);

    // (1) Ceiling check — strongest reject signal.
    if max_percentile > 100 {
        return AdmissionReport {
            verdict: AdmissionVerdict::Reject {
                reason: RejectReason::ExceedsCeilingAtCalibration,
            },
            certificates,
            polynomial_degree: None,
            max_percentile,
        };
    }

    // (2/3/4) Polynomial envelope test.
    let polynomial_degree = polynomial_degree_estimate(target, POLY_SAMPLE_SIZE);
    let verdict = match polynomial_degree {
        Some(d) if d <= POLY_DETECTOR_TIGHT_DEGREE => {
            AdmissionVerdict::AdmitPrimitiveRecursive { degree_estimate: d }
        }
        Some(_) => AdmissionVerdict::AdmitWithLegacyGuards,
        None => AdmissionVerdict::Reject {
            reason: RejectReason::NonPolynomialGrowth,
        },
    };

    AdmissionReport {
        verdict,
        certificates,
        polynomial_degree,
        max_percentile,
    }
}

/// Pre-baked policy: gate for `gnexec`-style call-depth guards. The
/// caller's `step_at` function should be a closure that estimates
/// step count from a call-depth `n` (e.g., for naive Fibonacci that
/// might be 2^n). Returns an AdmissionVerdict directly.
pub fn gate_call_depth<F: Fn(u32) -> u64 + Copy>(step_at: F) -> AdmissionVerdict {
    decide_admission(step_at).verdict
}

/// Pre-baked policy: gate for `multi_file`-style BFS-import guards.
/// The caller's `imports_at_depth` function should return the fan-out
/// count at BFS depth n. Returns an AdmissionVerdict directly.
pub fn gate_bfs_fanout<F: Fn(u32) -> u64 + Copy>(imports_at_depth: F) -> AdmissionVerdict {
    decide_admission(imports_at_depth).verdict
}

/// FOIL vacuum license. True exactly when the verdict is
/// `AdmitPrimitiveRecursive` — the only verdict whose semantics read
/// "caller may proceed with NO additional depth/time guard".
///
/// The vacuum is the guard-free execution region that verdict licenses:
/// the target's growth class is certified below the Ackermann ceiling
/// on the calibration window (the descent to the nadir is free — see
/// `Gnosis/FoilVacuumAdmission.lean` in open-source/gnosis-math for the
/// kernel-checked witness that the dropped guards are vacuous there),
/// so per-step growth-class guards spend cycles checking a condition
/// that provably cannot fire.
///
/// What this licenses dropping:
/// - `gnexec.rs`: the wall-clock deadline pulse (`check_deadline`'s
///   `Instant::now()` reads on every topology hop).
/// - `multi_file.rs`: the BFS `max_depth` truncation (the visited-set
///   on a finite import graph already bounds the traversal).
///
/// What this does NOT license dropping: physical machine limits. The
/// `max_call_depth` OS-stack backstop in `gnexec.rs` guards thread
/// stack exhaustion, which is a property of the machine, not of the
/// target's growth class; it stays in force inside the vacuum.
///
/// `AdmitWithLegacyGuards` is by construction NOT a license — that
/// verdict is the honest "the calibration window doesn't bind tightly
/// enough" answer, and `Reject` obviously isn't.
pub fn vacuum_licensed(verdict: AdmissionVerdict) -> bool {
    matches!(verdict, AdmissionVerdict::AdmitPrimitiveRecursive { .. })
}

/// Structural step envelope extracted from a program's GG topologies —
/// the per-target evidence that replaces the old hardcoded quadratic
/// proxy.
///
/// - `loop_nesting`: the effective nesting degree — per-topology
///   nesting depth of unbounded loops (literal-trip-count loops are
///   excluded: they multiply step counts by a source-text constant,
///   not by the input), summed across topologies. Nesting depth bounds
///   the polynomial degree of the step count in the input size;
///   sequential loops share a nesting level and do not escalate it
///   (Lean: `seq_composition_certified`), while the cross-topology sum
///   conservatively dominates call composition.
/// - `back_edges`: true when some topology contains a cycle among its
///   NON-Loop nodes. Structured loops cycle only through their Loop
///   node; any other cycle is control flow the estimator does not
///   model, so it must refuse to certify a degree.
/// - `call_cycles`: true when the (conservatively over-approximated)
///   call graph between topologies has a cycle — self or mutual
///   recursion. Tree recursion is the exact pathology the wall-clock
///   guard targets: loop-free frames, small depth, exponential total
///   call count. Recursion makes a loop-count degree meaningless, so
///   the estimator refuses to certify.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Default)]
pub struct TopologyStepEnvelope {
    pub loop_nesting: u32,
    pub back_edges: bool,
    pub call_cycles: bool,
}

/// Verdict policy for a structural envelope — the Rust mirror of
/// `estimatorDegree` in `Gnosis/FoilVacuumAdmission.lean` (gnosis-math,
/// theorem `estimator_sound`).
///
/// Degree mapping: monomial degree = effective nesting degree. The
/// kernel is consulted only for degrees 0..=2, because the degree-3 monomial
/// already breaches the window ceiling at n=2 (2³ = 8 > 4 — the Lean
/// witness is `estimator_cubic_breaches_window`); letting it through
/// would convert benign three-loop programs into ceiling rejects and
/// break legacy semantics. Those programs — and any topology with
/// unmodeled cycles — get the honest `AdmitWithLegacyGuards`: run, but
/// the calibration window doesn't bind tightly enough to license the
/// vacuum.
///
/// This policy can never `Reject`: structural loop counts are evidence
/// about growth in the input size, not proof of pathology. Rejection
/// stays reserved for callers with real step-count probes.
pub fn gate_step_envelope(envelope: TopologyStepEnvelope) -> AdmissionVerdict {
    if envelope.back_edges || envelope.call_cycles {
        return AdmissionVerdict::AdmitWithLegacyGuards;
    }
    match envelope.loop_nesting {
        0 => gate_call_depth(|_n: u32| 1u64),
        1 => gate_call_depth(|n: u32| n as u64),
        2 => gate_call_depth(|n: u32| (n as u64) * (n as u64)),
        _ => AdmissionVerdict::AdmitWithLegacyGuards,
    }
}

/// Structural termination: no unbounded loops, no unmodeled cycles,
/// and no recursion. Literal-trip-count loops are permitted — their
/// step contribution is a constant fixed in the source text, so the
/// program's total step count stays input-independent (Lean:
/// `const_trip_preserves_independence`). For such a program the call
/// graph is a DAG and every
/// frame is a DAG walk, so total step count is bounded by the product
/// of topology sizes along call chains — finite and small, with no
/// dependence on the depth backstop to cut anything off. Only then is
/// the wall-clock guard provably not load-bearing and the vacuum may
/// engage by default rather than by opt-in.
///
/// Recursion-freedom is REQUIRED here, not optional: a loop-free
/// tree-recursive program (naive fib) has bounded depth but
/// exponential total call count — dropping its deadline by default
/// would hang exactly the workloads the guard was built for.
pub fn structurally_terminating(envelope: TopologyStepEnvelope) -> bool {
    !envelope.back_edges && !envelope.call_cycles && envelope.loop_nesting == 0
}

/// Session-stable FOIL vacuum license.
///
/// The envelope is a pure function of the scanned topologies — no
/// request datum enters it — so a license computed once at load time
/// remains valid for every request walked against the same topologies.
/// Lean witnesses: `request_license_constant` (the license ignores the
/// request) and `session_vacuum_noop` (one load-time certification
/// makes guard removal a no-op across an entire request list) in
/// `Gnosis/FoilVacuumAdmission.lean` (gnosis-math).
///
/// One-shot callers (gnexec main) build this per invocation; a
/// resident walker should build it once at topology load and call
/// `engages` per request instead of re-running admission.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct SessionVacuumLicense {
    pub verdict: AdmissionVerdict,
    /// Loop-free, cycle-free, recursion-free: the shape for which the
    /// vacuum engages by default rather than by opt-in.
    pub structural: bool,
}

impl SessionVacuumLicense {
    /// Certify once from the structural envelope.
    pub fn from_envelope(envelope: TopologyStepEnvelope) -> Self {
        Self {
            verdict: gate_step_envelope(envelope),
            structural: structurally_terminating(envelope),
        }
    }

    /// A license for a synthetic (non-estimator) verdict: never
    /// structural, because no topology evidence backs it.
    pub fn synthetic(verdict: AdmissionVerdict) -> Self {
        Self {
            verdict,
            structural: false,
        }
    }

    /// Whether the wall-clock guard may be dropped for a request walk,
    /// given the caller's opt-in and kill-switch state. Pure and
    /// request-independent: the same answer holds for every request in
    /// the session.
    pub fn engages(&self, requested: bool, disabled: bool) -> bool {
        !disabled && (requested || self.structural) && vacuum_licensed(self.verdict)
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use distributed_inference::ackermann_certificate::ackermann_ceiling;

    /// Lean oracle mirror — same values pinned by
    /// `Gnosis/AckermannRuntimeOracle.lean`.
    fn ackermann_value_at(n: u32) -> u64 {
        ackermann_ceiling(n).expect("calibration window")
    }

    /// `target = |_| 0` is a degree-0 polynomial (constant). The
    /// finite-difference detector returns Some(0). All percentiles
    /// are 0, so no ceiling reject.
    #[test]
    fn admits_zero_runtime() {
        let report = decide_admission(|_n: u32| 0u64);
        match report.verdict {
            AdmissionVerdict::AdmitPrimitiveRecursive { degree_estimate } => {
                assert!(
                    degree_estimate == 0 || degree_estimate == 1,
                    "expected degree 0 or 1 for constant-zero, got {}",
                    degree_estimate
                );
            }
            v => panic!("expected AdmitPrimitiveRecursive, got {:?}", v),
        }
        assert_eq!(report.max_percentile, 0);
    }

    /// `target = |n| n` is a degree-1 polynomial. Detector pins d=1.
    #[test]
    fn admits_linear() {
        let report = decide_admission(|n: u32| n as u64);
        assert_eq!(
            report.verdict,
            AdmissionVerdict::AdmitPrimitiveRecursive { degree_estimate: 1 }
        );
        assert_eq!(report.polynomial_degree, Some(1));
    }

    /// `target = |n| n*n` is a degree-2 polynomial. Detector pins d=2.
    #[test]
    fn admits_quadratic() {
        let report = decide_admission(|n: u32| (n as u64) * (n as u64));
        assert_eq!(
            report.verdict,
            AdmissionVerdict::AdmitPrimitiveRecursive { degree_estimate: 2 }
        );
        assert_eq!(report.polynomial_degree, Some(2));
    }

    /// Exponential 2^n must fail the polynomial envelope test on
    /// sample window of 8. Percentiles stay below ceiling (2^3 = 8 <
    /// 27), so we route through NonPolynomialGrowth rather than the
    /// ceiling branch.
    #[test]
    fn rejects_exponential() {
        let report = decide_admission(|n: u32| 1u64 << n);
        assert_eq!(
            report.verdict,
            AdmissionVerdict::Reject {
                reason: RejectReason::NonPolynomialGrowth
            }
        );
        assert_eq!(report.polynomial_degree, None);
    }

    /// Doubling the Lean oracle values puts every calibration point
    /// at 200% of the ceiling — strongest reject signal.
    /// We use u64::MAX for n > 3 since there is no numeric ceiling
    /// there; the ceiling check on the calibration window (n ≤ 3)
    /// fires first and short-circuits the polynomial sample.
    #[test]
    fn rejects_naive_ackermann_proxy() {
        let report = decide_admission(|n: u32| {
            if n <= 3 {
                ackermann_value_at(n) * 2
            } else {
                u64::MAX
            }
        });
        assert_eq!(
            report.verdict,
            AdmissionVerdict::Reject {
                reason: RejectReason::ExceedsCeilingAtCalibration
            }
        );
        // Percentile at every calibration point is 200 (2x ceiling)
        // so max_percentile must reflect that.
        assert!(report.max_percentile >= 200);
    }

    /// Tail-call / iterative Fibonacci has linear step growth.
    /// `gate_call_depth` admits it as primitive-recursive degree 1.
    #[test]
    fn gate_call_depth_admits_fibonacci_proxy_linear() {
        let verdict = gate_call_depth(|n: u32| n as u64);
        assert_eq!(
            verdict,
            AdmissionVerdict::AdmitPrimitiveRecursive { degree_estimate: 1 }
        );
    }

    /// Naive recursive Fibonacci has 2^n call-tree size. The gate
    /// must reject — this is the exact pathology the legacy
    /// `max_call_depth + deadline` guard was reactively papering over.
    #[test]
    fn gate_call_depth_rejects_naive_fibonacci_proxy() {
        let verdict = gate_call_depth(|n: u32| 1u64 << n);
        assert_eq!(
            verdict,
            AdmissionVerdict::Reject {
                reason: RejectReason::NonPolynomialGrowth
            }
        );
    }

    /// `AdmissionReport::max_percentile` must equal the max of the
    /// `percentile` field across the `certificates` vector — the
    /// report cannot disagree with its own certify() output.
    #[test]
    fn report_max_percentile_tracks_certify_output() {
        // Identity target: n=0 ⇒ 0%, n=1 ⇒ 50%, n=2 ⇒ 50%, n=3 ⇒ 11%.
        // Max is 50.
        let report = decide_admission(|n: u32| n as u64);
        let expected_max = report
            .certificates
            .iter()
            .map(|c| c.percentile)
            .max()
            .unwrap();
        assert_eq!(report.max_percentile, expected_max);
        assert_eq!(report.max_percentile, 50);

        // Constant-zero target: every percentile is 0, max is 0.
        let zero_report = decide_admission(|_n: u32| 0u64);
        assert_eq!(zero_report.max_percentile, 0);
        assert_eq!(zero_report.certificates.len(), 4);
        for c in &zero_report.certificates {
            assert_eq!(c.percentile, 0);
        }
    }

    /// The vacuum license is granted exactly on certified
    /// primitive-recursive verdicts: linear admits license the vacuum,
    /// `AdmitWithLegacyGuards` and both reject shapes do not.
    #[test]
    fn vacuum_licensed_only_for_certified_admits() {
        // Certified linear ⇒ licensed.
        assert!(vacuum_licensed(gate_call_depth(|n: u32| n as u64)));
        // Exponential reject ⇒ not licensed.
        assert!(!vacuum_licensed(gate_call_depth(|n: u32| 1u64 << n)));
        // Honest "window doesn't bind" ⇒ not licensed.
        assert!(!vacuum_licensed(AdmissionVerdict::AdmitWithLegacyGuards));
        // Ceiling reject ⇒ not licensed.
        assert!(!vacuum_licensed(AdmissionVerdict::Reject {
            reason: RejectReason::ExceedsCeilingAtCalibration
        }));
    }

    /// The envelope policy mirrors the Lean `estimatorDegree` map:
    /// nesting degrees 0..=2 certify (monomial degree = nesting
    /// degree), degree ≥ 3 and unmodeled cycles fall back to legacy
    /// guards, and the policy never rejects.
    #[test]
    fn gate_step_envelope_mirrors_lean_estimator() {
        let env = |loop_nesting, back_edges| TopologyStepEnvelope {
            loop_nesting,
            back_edges,
            call_cycles: false,
        };
        assert!(matches!(
            gate_step_envelope(env(0, false)),
            AdmissionVerdict::AdmitPrimitiveRecursive { .. }
        ));
        assert_eq!(
            gate_step_envelope(env(1, false)),
            AdmissionVerdict::AdmitPrimitiveRecursive { degree_estimate: 1 }
        );
        assert_eq!(
            gate_step_envelope(env(2, false)),
            AdmissionVerdict::AdmitPrimitiveRecursive { degree_estimate: 2 }
        );
        // Degree 3 breaches the window ceiling at n=2 (8 > 4) — the
        // honest verdict is legacy guards, never a reject.
        assert_eq!(
            gate_step_envelope(env(3, false)),
            AdmissionVerdict::AdmitWithLegacyGuards
        );
        // Unmodeled cycles refuse certification regardless of loops.
        assert_eq!(
            gate_step_envelope(env(0, true)),
            AdmissionVerdict::AdmitWithLegacyGuards
        );
        // Recursion refuses certification too: nesting degrees say
        // nothing about growth once the call graph has a cycle.
        assert_eq!(
            gate_step_envelope(TopologyStepEnvelope {
                loop_nesting: 0,
                back_edges: false,
                call_cycles: true,
            }),
            AdmissionVerdict::AdmitWithLegacyGuards
        );
    }

    /// Structural termination (the auto-vacuum criterion) holds exactly
    /// for the loop-free, cycle-free, recursion-free envelope. The
    /// recursion clause is load-bearing: naive fib is loop-free with
    /// bounded depth but exponential total calls — the deadline's exact
    /// target — so it must never auto-enter the vacuum.
    #[test]
    fn structurally_terminating_only_loop_and_cycle_free() {
        let env = |loop_nesting, back_edges, call_cycles| TopologyStepEnvelope {
            loop_nesting,
            back_edges,
            call_cycles,
        };
        assert!(structurally_terminating(env(0, false, false)));
        assert!(!structurally_terminating(env(1, false, false)));
        assert!(!structurally_terminating(env(0, true, false)));
        assert!(!structurally_terminating(env(0, false, true)));
        // And the structural envelope's verdict licenses the vacuum.
        assert!(vacuum_licensed(gate_step_envelope(env(0, false, false))));
        assert!(!vacuum_licensed(gate_step_envelope(env(0, true, false))));
        assert!(!vacuum_licensed(gate_step_envelope(env(0, false, true))));
    }

    /// The session license is pure in the request: `engages` depends
    /// only on load-time state (verdict, structural flag) plus the
    /// caller's opt-in/kill-switch, mirroring the Lean
    /// `request_license_constant` / `session_vacuum_noop` pair.
    #[test]
    fn session_license_engagement_truth_table() {
        let structural = SessionVacuumLicense::from_envelope(TopologyStepEnvelope::default());
        assert!(structural.structural);
        // Structural ⇒ engages by default; kill switch overrides all.
        assert!(structural.engages(false, false));
        assert!(structural.engages(true, false));
        assert!(!structural.engages(false, true));
        assert!(!structural.engages(true, true));

        let loopy = SessionVacuumLicense::from_envelope(TopologyStepEnvelope {
            loop_nesting: 1,
            back_edges: false,
            call_cycles: false,
        });
        assert!(!loopy.structural);
        // Certified but not structural ⇒ opt-in only.
        assert!(!loopy.engages(false, false));
        assert!(loopy.engages(true, false));
        assert!(!loopy.engages(true, true));

        let recursive = SessionVacuumLicense::from_envelope(TopologyStepEnvelope {
            loop_nesting: 0,
            back_edges: false,
            call_cycles: true,
        });
        // Unlicensed verdict ⇒ never engages, even with opt-in.
        assert!(!recursive.engages(true, false));

        // Synthetic licenses carry no structural claim.
        let synthetic = SessionVacuumLicense::synthetic(gate_call_depth(|n: u32| n as u64));
        assert!(!synthetic.structural);
        assert!(synthetic.engages(true, false));
        assert!(!synthetic.engages(false, false));
    }

    /// `gate_bfs_fanout` mirrors `gate_call_depth` for the multi_file
    /// import-BFS shape: a constant fan-out (well-bounded import
    /// graph) admits.
    #[test]
    fn gate_bfs_fanout_admits_constant_fanout() {
        let verdict = gate_bfs_fanout(|_n: u32| 4u64);
        // Constant-4 ⇒ percentile at n=0 = 400 ⇒ ceiling-exceeded
        // reject. This is the right answer: a fan-out of 4 at depth 0
        // means "every file pulls in 4 more", which IS exponential
        // growth in the BFS frontier. The gate catches that the same
        // way it catches naive fib.
        assert_eq!(
            verdict,
            AdmissionVerdict::Reject {
                reason: RejectReason::ExceedsCeilingAtCalibration
            }
        );
    }
}
